input.command:
# Step 2: Patch es-transform StatefulSet - fix image and add volumes
kubectl patch statefulset -n elasticsearch es-transform --type=json -p='[
  {
    "op": "replace",
    "path": "/spec/template/spec/containers/0/image",
    "value": "docker.elastic.co/elasticsearch/elasticsearch:8.11.1"
  },
  {
    "op": "add",
    "path": "/spec/template/spec/volumes/-",
    "value": {
      "name": "certs",
      "secret": {
        "secretName": "es-http-tls",
        "defaultMode": 420
      }
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/volumes/-",
    "value": {
      "name": "file-realm",
      "secret": {
        "secretName": "es-file-realm-aggregate",
        "defaultMode": 420,
        "items": [
          {"key": "users", "path": "users"},
          {"key": "users_roles", "path": "users_roles"}
        ]
      }
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "certs",
      "mountPath": "/usr/share/elasticsearch/config/certs",
      "readOnly": true
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "file-realm",
      "mountPath": "/usr/share/elasticsearch/config/users",
      "subPath": "users",
      "readOnly": true
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "file-realm",
      "mountPath": "/usr/share/elasticsearch/config/users_roles",
      "subPath": "users_roles",
      "readOnly": true
    }
  }
]'

