ELASTIC_PASS=$(kubectl get secret -n elasticsearch elastic-password -o jsonpath='{.data.password}' | base64 -d)
ES_IP="10.96.57.253"

# Create the transform events-by-service
kubectl exec -n elasticsearch curl-test -- curl -sk -u "elastic:${ELASTIC_PASS}" \
  -XPUT "https://${ES_IP}:9200/_transform/events-by-service" \
  -H "Content-Type: application/json" \
  -d '{
    "source": {"index": "app-events"},
